```
const Discord = require('discord.js');
const client = new Discord.Client();

client.commands = new Discord.Collection();

const banCommand = new Discord.CommandBuilder()
 .setName('ban')
 .setDescription('Bans a user from the server.')
 .addArgument(new Discord.Argument('userID', 'The ID of the user to ban'))
 .setGuildId('YOUR_GUILD_ID')
 .setCategory('moderation')
 .setCooldown(3000) // set cooldown to 3 seconds
 .addslash()
 .build();

client.on('guildCreate', guild => {
  guild.commands.add(banCommand);
});

client.on('guildDelete', guild => {
  guild.commands.remove(banCommand);
});

client.on('message', message => {
  if (message.author.id!== client.user.id) {
    const args = message.content.split(' ');
    if (args[0] === '!ban') {
      const userID = args[1];
      const user = message.guild.members.get(userID);
      if (user) {
        user.ban();
        message.reply(`Banned ${user.username} from the server!`);
      } else {
        message.reply('Please provide a valid user ID.');
      }
    }
  }
});

client.login('YOUR_BOT_TOKEN');
```
