  // Your code to determine if the value is of type ValidType goes here
  return false; // By returning false, you're indicating that the value is not of type ValidType
}

let myValue: any = 'hello';

if (isValidType(myValue)) {
  // myValue is of type ValidType
  let newValue: ValidType = myValue; // Here, the type of newValue is inferred to be ValidType

  console.log(newValue); // Output: 'hello'
} else {
  // myValue is not of type ValidType
  console.log('Invalid value');
}
